1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioResult {
52	  results: StepResult[];
53	}
54	
55	const PROCESSING_FEE = 5;
56	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
57	
58	const EPSILON = 1e-9;
59	
60	const roundUp = (n: number): number => Math.ceil(n - EPSILON);
61	const roundDown = (n: number): number => Math.floor(n + EPSILON);
62	
63	const MAIN_ITEM_BASE_PREMIUMS: Record<string, number> = {
64	  sword: 100,
65	  amulet: 60,
66	  staff: 80,
67	  potion: 40,
68	};
69	
70	const INSURANCE_VALUES: Record<string, number> = {
71	  sword: 1000,
72	  amulet: 600,
73	  staff: 800,
74	  potion: 400,
75	  rune: 250,
76	  moonstone: 250,
77	};
78	
79	const DEDUCTIBLE = 100;
80	const CAP_MULTIPLIER = 2;
81	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
82	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
83	
84	const insuranceValue = (type: string): number => INSURANCE_VALUES[type] ?? 0;
85	const policyCap = (items: Item[]): number =>
86	  CAP_MULTIPLIER * items.reduce((sum, item) => sum + insuranceValue(item.type), 0);
87	
88	const COMPONENT_BASE_PREMIUMS: Record<string, number> = {
89	  rune: 25,
90	  moonstone: 25,
91	};
92	
93	const ITEM_BASE_PREMIUMS: Record<string, number> = {
94	  ...MAIN_ITEM_BASE_PREMIUMS,
95	  ...COMPONENT_BASE_PREMIUMS,
96	};
97	
98	const COMPONENT_TYPES = new Set(Object.keys(COMPONENT_BASE_PREMIUMS));
99	const BLOCK_SIZE = 3;
100	const BLOCK_BASE = 60;
101	
102	const CURSE_SURCHARGE_RATE = 0.5;
103	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
104	const HIGH_ENCHANTMENT_THRESHOLD = 5;
105	const LOYALTY_DISCOUNT_RATE = 0.2;
106	const LOYALTY_THRESHOLD_YEARS = 2;
107	const FOLLOWUP_DISCOUNT_RATE = 0.15;
108	
109	const itemBase = (type: string): number => ITEM_BASE_PREMIUMS[type] ?? 0;
110	
111	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
112	
113	const componentGroupBase = (count: number, unitBase: number): number => {
114	  if (count === BLOCK_SIZE) return BLOCK_BASE;
115	  return count * unitBase;
116	};
117	
118	const itemSurchargeRate = (item: Item): number => {
119	  let rate = 0;
120	  if (item.cursed) rate += CURSE_SURCHARGE_RATE;
121	  if (enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD) {
122	    rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
123	  }
124	  return rate;
125	};
126	
127	const itemSurcharge = (item: Item, base: number): number =>
128	  base * itemSurchargeRate(item);
129	
130	const policyModifierRate = (customer: Customer, priorQuoteCount: number): number => {
131	  let rate = FIRST_INSURANCE_SURCHARGE_RATE;
132	  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
133	    rate -= LOYALTY_DISCOUNT_RATE;
134	  }
135	  if (priorQuoteCount >= 1) {
136	    rate -= FOLLOWUP_DISCOUNT_RATE;
137	  }
138	  return rate;
139	};
140	
141	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
142	
143	const componentsBaseTotal = (components: Item[]): number => {
144	  const counts = new Map<string, number>();
145	  for (const item of components) {
146	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
147	  }
148	  let total = 0;
149	  for (const [type, count] of counts) {
150	    total += componentGroupBase(count, itemBase(type));
151	  }
152	  return total;
153	};
154	
155	const mainItemsBaseTotal = (mainItems: Item[]): number =>
156	  mainItems.reduce((sum, item) => sum + itemBase(item.type), 0);
157	
158	const mainItemsSurchargeTotal = (mainItems: Item[]): number =>
159	  mainItems.reduce((sum, item) => sum + itemSurcharge(item, itemBase(item.type)), 0);
160	
161	const quotePremium = (items: Item[], customer: Customer, priorQuoteCount: number): number => {
162	  const mainItems = items.filter((item) => !isComponent(item));
163	  const components = items.filter(isComponent);
164	
165	  const policyBase = mainItemsBaseTotal(mainItems) + componentsBaseTotal(components);
166	  const itemSurchargeTotal = mainItemsSurchargeTotal(mainItems);
167	  const policyModifierTotal = policyBase * policyModifierRate(customer, priorQuoteCount);
168	
169	  const total = policyBase + itemSurchargeTotal + policyModifierTotal;
170	  return roundUp(total) + PROCESSING_FEE;
171	};
172	
173	const coveredDamageAmount = (insuredItem: Item, damageAmount: number): number => {
174	  if (enchantmentLevel(insuredItem) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD) {
175	    return damageAmount * HIGH_ENCHANTMENT_PAYOUT_RATE;
176	  }
177	  return damageAmount;
178	};
179	
180	const damagePayout = (damage: Damage, insuredItem: Item): number =>
181	  Math.max(0, coveredDamageAmount(insuredItem, damage.amount) - DEDUCTIBLE);
182	
183	const findInsuredItem = (items: Item[], itemType: string): Item =>
184	  items.find((item) => item.type === itemType) as Item;
185	
186	const totalPayout = (damages: Damage[], items: Item[]): number =>
187	  damages.reduce(
188	    (sum, damage) => sum + damagePayout(damage, findInsuredItem(items, damage.itemType)),
189	    0,
190	  );
191	
192	const policyItems = (scenario: Scenario, policyIndex: number): Item[] =>
193	  (scenario.steps[policyIndex] as QuoteStep).items;
194	
195	const currentCap = (
196	  remainingCaps: Map<number, number>,
197	  policy: number,
198	  items: Item[],
199	): number => remainingCaps.get(policy) ?? policyCap(items);
200	
201	const processClaim = (
202	  step: ClaimStep,
203	  scenario: Scenario,
204	  remainingCaps: Map<number, number>,
205	): ClaimResult => {
206	  const items = policyItems(scenario, step.policy);
207	  const capBefore = currentCap(remainingCaps, step.policy, items);
208	  const uncappedPayout = roundDown(totalPayout(step.incident.damages, items));
209	  const payout = Math.min(uncappedPayout, capBefore);
210	  const remainingCap = capBefore - payout;
211	  remainingCaps.set(step.policy, remainingCap);
212	  return { payout, remainingCap };
213	};
214	
215	const processStep = (
216	  step: Step,
217	  scenario: Scenario,
218	  priorQuoteCount: number,
219	  remainingCaps: Map<number, number>,
220	): StepResult => {
221	  if (step.op === "quote") {
222	    return { premium: quotePremium(step.items, scenario.customer, priorQuoteCount) };
223	  }
224	  return processClaim(step, scenario, remainingCaps);
225	};
226	
227	const KNOWN_ITEM_TYPES = new Set(Object.keys(INSURANCE_VALUES));
228	
229	const isQuoteStep = (step: Step): step is QuoteStep => step.op === "quote";
230	const isClaimStep = (step: Step): step is ClaimStep => step.op === "claim";
231	
232	const quotedItems = (scenario: Scenario): Item[] =>
233	  scenario.steps.filter(isQuoteStep).flatMap((step) => step.items);
234	
235	const insuredItemTypes = (scenario: Scenario, policy: number): Set<string> =>
236	  new Set(policyItems(scenario, policy).map((item) => item.type));
237	
238	const validateQuotedItemsAreKnown = (scenario: Scenario): void => {
239	  for (const item of quotedItems(scenario)) {
240	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
241	      throw new Error(`unknown item type: ${item.type}`);
242	    }
243	  }
244	};
245	
246	const claimDamages = (scenario: Scenario): { step: ClaimStep; damage: Damage }[] =>
247	  scenario.steps
248	    .filter(isClaimStep)
249	    .flatMap((step) => step.incident.damages.map((damage) => ({ step, damage })));
250	
251	const validateClaimDamagesReferenceInsuredItems = (scenario: Scenario): void => {
252	  for (const { step, damage } of claimDamages(scenario)) {
253	    const insured = insuredItemTypes(scenario, step.policy);
254	    if (!insured.has(damage.itemType)) {
255	      throw new Error(`claim references item "${damage.itemType}" not in policy`);
256	    }
257	  }
258	};
259	
260	const validateClaimDamageAmountsAreNonNegative = (scenario: Scenario): void => {
261	  for (const { damage } of claimDamages(scenario)) {
262	    if (damage.amount < 0) {
263	      throw new Error(`negative damage amount: ${damage.amount}`);
264	    }
265	  }
266	};
267	
268	const countByType = <T extends { type?: string } | Item | Damage>(
269	  entries: { itemType?: string; type?: string }[] | Item[],
270	): Map<string, number> => {
271	  const counts = new Map<string, number>();
272	  for (const entry of entries as { itemType?: string; type?: string }[]) {
273	    const key = entry.itemType ?? entry.type ?? "";
274	    counts.set(key, (counts.get(key) ?? 0) + 1);
275	  }
276	  return counts;
277	};
278	
279	const validateClaimDamageCountsFitPolicy = (scenario: Scenario): void => {
280	  for (const step of scenario.steps.filter(isClaimStep)) {
281	    const insuredCounts = countByType(policyItems(scenario, step.policy));
282	    const damageCounts = countByType(step.incident.damages);
283	    for (const [type, count] of damageCounts) {
284	      if (count > (insuredCounts.get(type) ?? 0)) {
285	        throw new Error(`claim has more "${type}" damages than insured`);
286	      }
287	    }
288	  }
289	};
290	
291	export const validateScenario = (scenario: Scenario): void => {
292	  validateQuotedItemsAreKnown(scenario);
293	  validateClaimDamagesReferenceInsuredItems(scenario);
294	  validateClaimDamageAmountsAreNonNegative(scenario);
295	  validateClaimDamageCountsFitPolicy(scenario);
296	};
297	
298	export const processScenario = (scenario: Scenario): ScenarioResult => {
299	  let priorQuoteCount = 0;
300	  const remainingCaps = new Map<number, number>();
301	  const results: StepResult[] = scenario.steps.map((step) => {
302	    const result = processStep(step, scenario, priorQuoteCount, remainingCaps);
303	    if (step.op === "quote") priorQuoteCount++;
304	    return result;
305	  });
306	  return { results };
307	};
