5	const runCli = (input: string): Promise<{ code: number; stdout: string; stderr: string }> =>
6	  new Promise((resolve, reject) => {
7	    const child = spawn("npx", ["tsx", "src/cli.ts"], { stdio: ["pipe", "pipe", "pipe"] });
8	    let stdout = "";
9	    let stderr = "";
10	    child.stdout.on("data", (chunk) => (stdout += chunk.toString()));
11	    child.stderr.on("data", (chunk) => (stderr += chunk.toString()));
12	    child.on("error", reject);
13	    child.on("close", (code) => resolve({ code: code ?? 0, stdout, stderr }));
14	    child.stdin.write(input);
15	    child.stdin.end();
16	  });
